import re

# generated by scripts/generate_identifier_pattern.py
# GRAIL: the upstream pattern packs the full Unicode XID_Continue
# range into a single character class.  Grail's Python tokenizer
# doesn't carry the high-codepoint characters through to the
# compiled pattern, so trim to ASCII letters / digits / underscore.
# Adequate for Flask hello-world templates, which only reference
# ASCII variable names; non-ASCII identifiers in template variables
# would fail this match.
pattern = re.compile(r"[A-Za-z_][A-Za-z_0-9]*")
